public int numDecodings(String s, int k) {
    int n = s.length();
    int[] dp = new int[n + 1];
    dp[n] = 1;
    int MOD = 1000000007;

    for (int i = n - 1; i >= 0; i--) {
        long num = 0;
        for (int j = i; j < n && num <= k; j++) {
            num = num * 10 + s.charAt(j) - '0';
            if (num >= 1 && num <= k) {
                dp[i] = (dp[i] + dp[j + 1]) % MOD;
            }
        }
    }
    return dp[0];
}
